function parseCSVLine(line) {
  if (typeof line !== "string") return null;

  const fields = [];
  let i = 0;
  const n = line.length;

  while (true) {
    let field = "";

    if (i < n && line[i] === '"') {
      // Quoted field
      i++;
      let closed = false;
      while (i < n) {
        if (line[i] === '"') {
          if (i + 1 < n && line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++;
            closed = true;
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      if (!closed) return null; // unterminated quote
      if (i < n && line[i] !== ",") return null; // junk after closing quote
    } else {
      // Unquoted field
      while (i < n && line[i] !== ",") {
        if (line[i] === '"') return null; // quote inside unquoted field
        field += line[i];
        i++;
      }
    }

    fields.push(field);

    if (i < n && line[i] === ",") {
      i++;
      continue;
    }
    break;
  }

  return fields;
}
